<?php/** * Created by PhpStorm. * User: Cyril * Date: 21/07/2016 * Time: 08:55 *///require_once('./functions/crypt_pass.func.php');class DatabaseWorker{    private $table_name;    private $db;    private $displayed_fields;    private $compte_principal;    private $widget_name = 'Tableau';    private $widget_size = 12;    private $widget_boxed = false;    private $labels_table;    private $add = false;    private $delete = false;    private $modify = false;    private $delete_notify;    private $delete_redirect;    private $add_notify;    private $add_redirect;    private $modify_notify;    private $modify_redirect;    private $tab_where;    private $counter_innerjoin = 0;    private $tab_innerjoin;    private $tab_hiddens;    private $tab_hiddens_add;    private $sql;    private $no_modify_fields;    private $password_fields;    private $tab_date;    private $tab_date_time;    private $debug;    private $order_by;    private $sens_order_by;    private $open_link;    private $compteur_open_link = 0;    private $maxcountvalue;    private $tab_ifvalue;    private $ifvaluecounter = 0;    private $hide_fields;    private $if_zero_replace_by_today;    private $tab_data_type_form;    private $noprintmodal = 0;    private $tab_modals;    private $tab_color_picker;    private $tab_wysiwyg;    private $data_table = 'table table-striped table-bordered table-hover order-column table-datatable';    public function __construct($table_name, $compte_principal = true)    {        $this->table_name = $table_name;        $this->compte_principal = $compte_principal;        $this->db = new MySQL();        $this->displayed_fields = Array();        $this->labels_table = Array();        $this->tab_innerjoin = Array();        $this->tab_hiddens = Array();        $this->tab_hiddens_add = Array();        $this->no_modify_fields = Array();        $this->tab_date = Array();        $this->tab_date_time = Array();        $this->open_link = Array();        $this->password_fields = Array();        $this->hide_fields = Array();        $this->tab_data_type_form = Array();        $this->tab_modals = Array();        $this->tab_color_picker = Array();        $this->tab_wysiwyg = Array();    }    public function setDataTable()    {        $this->data_table = 'table table-striped table-bordered table-hover order-column table-datatable';    }    public function noDatatable()    {        $this->data_table = 'table table-striped table-bordered table-hover order-column';    }    public function debug()    {        $this->debug = true;    }    public function addDateFields($fields, $if_zero_replace_by_today = true)    {        if (is_array($fields))            $this->tab_date = $fields;        else            $this->tab_date[] = $fields;        $this->if_zero_replace_by_today = $if_zero_replace_by_today;    }    public function addDateTimeFields($fields)    {        if (is_array($fields))            $this->tab_date_time = $fields;        else            $this->tab_date_time[] = $fields;    }    public function addWysiwygFields($fields)    {        if (is_array($fields))            $this->tab_wysiwyg = $fields;        else            $this->tab_wysiwyg[] = $fields;    }    public function addColorFields($fields)    {        if(is_array($fields))            $this->tab_color_picker = $fields;        else            $this->tab_color_picker[] = $fields;    }    public function innerJoin($table_joined, $field_to_replace, $new_field, $compte_principal = true, $forced = true, $unique = false)    {        $this->tab_innerjoin[$this->counter_innerjoin]['table_joined'] = $table_joined;        $this->tab_innerjoin[$this->counter_innerjoin]['field_to_replace'] = $field_to_replace;        $this->tab_innerjoin[$this->counter_innerjoin]['new_field'] = $new_field;        $this->tab_innerjoin[$this->counter_innerjoin]['compte_principal'] = $compte_principal;        $this->tab_innerjoin[$this->counter_innerjoin]['forced'] = $forced;        $this->tab_innerjoin[$this->counter_innerjoin]['unique'] = $unique;        $sql = 'SELECT id, ' . $new_field . ' FROM ' . $table_joined;        if ($compte_principal)            $sql .= ' WHERE compte_principal="' . $_SESSION['compte_principal'] . '" ';        $db = new MySQL();        $db->Query($sql);        $nb_ligne = $db->RowCount();        for ($i = 0; $i < $nb_ligne; $i++) {            $this->tab_innerjoin[$this->counter_innerjoin]['content'][$i]['id'] = $db->RecordsArray()[$i]['id'];            $this->tab_innerjoin[$this->counter_innerjoin]['content'][$i][$new_field] = $db->RecordsArray()[$i][$new_field];        }        $this->counter_innerjoin++;    }    private function delete()    {        if (!empty($_GET['delete'])) {            $tab = explode('.', $_GET['delete']);            $table = $this->db->SQLFix($tab[0]);            $id = $this->db->SQLFix($tab[1]);            if ($table == $this->table_name) {                $sql = 'DELETE FROM ' . $table . ' WHERE id = "' . $id . '" ';                if ($this->compte_principal)                    $sql .= ' AND compte_principal = "' . $_SESSION['compte_principal'] . '" ';                $this->db->Query($sql);                if ($this->db->Error()) {                    $erreur = new Danger('MySQL a retourné une erreur : <strong>' . $this->db->Error() . '</strong> &rarr; Table "<strong>' . $this->table_name . '</strong>"', false);                    $info = new Info('Requête MySQL : <strong>' . $this->sql . '</strong>', false);                    echo $erreur . $info;                    die();                }                if ($this->delete_notify)                    $_SESSION['notify'] = $this->delete_notify;                if ($this->delete_redirect) {                    header('location:' . $this->delete_redirect);                    die();                }            }        }    }    public function setMaxCountValue($field, $value, $table_contain_max, $field_contain_max, $where_field = 'compte_principal', $where_value = 0)    {        //die('ok');        $this->maxcountvalue['field'] = $field;        $this->maxcountvalue['value'] = $value;        $this->maxcountvalue['table'] = $table_contain_max;        $this->maxcountvalue['field_max'] = $field_contain_max;        $this->maxcountvalue['where_field'] = $where_field;        if ($where_value)            $this->maxcountvalue['where_value'] = $where_field;        else            $this->maxcountvalue['where_value'] = $_SESSION['compte_principal'];    }    private function update()    {        if (!empty($_POST) AND $_POST['table_name'] == $this->table_name) {            if ($_POST['id']) {                $sql = 'UPDATE ' . $this->table_name . ' SET ';                if(isset($_POST['_wysihtml5_mode']))                    $i= 1;                else                    $i = 0;                $count = count($_POST);                //die($count);                foreach ($_POST AS $key => $value) {                    if ($key != 'id' AND $key != 'table_name' AND $key !='_wysihtml5_mode') {                        $modify = true;                        if (in_array($key, $this->tab_date)) {                            $tab_date = explode('/', $value);                            $value = mktime(23, 59, 59, $tab_date['1'], $tab_date[0], $tab_date[2]);                        }                        if (in_array($key, $this->tab_date_time)) {                            $tab = explode(' ', $value);                            $tab_date = explode('/', $tab[0]);                            $tab_heure = explode(':', $tab[1]);                            $value = mktime($tab_heure[0], $tab_heure[1], 0, $tab_date['1'], $tab_date[0], $tab_date[2]);                        }                        if (in_array($key, $this->password_fields)) {                            if (empty($value))                                $modify = false;                            else                                $value = sha1($value);                        }                        $nouveau_field = str_replace('_submit', '', $key);                        if ($nouveau_field == $key) {                            $field = $this->db->SQLFix($key);                            $valeur = $this->db->SQLFix($value);                            if ($modify)                                $sql .= $field . '="' . $valeur . '"';                            if($this->compte_principal)                                $max = 3;                            else                                $max = 2;                            if ($i < $count - $max)                                $sql .= ', ';                        }                    }                    $i++;                }                foreach ($this->tab_hiddens AS $k => $v) {                    $key = $this->db->SQLFix($k);                    $val = $this->db->SQLFix($v);                    $sql .= ' , ' . $key . ' = "' . $val . '" ';                }                $id = $this->db->SQLFix($_POST['id']);                $sql .= ' WHERE id="' . $id . '" ';                if ($this->compte_principal)                    $sql .= ' AND compte_principal="' . $_SESSION['compte_principal'] . '"';                $sql = str_replace(', ,', ', ', $sql);                $sql = str_replace(',  WHERE', ' WHERE', $sql);                //die($sql);                $this->db->Query($sql);                if ($this->db->Error()) {                    $erreur = new Danger('MySQL a retourné une erreur : <strong>' . $this->db->Error() . '</strong> &rarr; Table "<strong>' . $this->table_name . '</strong>"', false);                    $info = new Info('Requête MySQL : <strong>' . $sql . '</strong>', false);                    echo $erreur . $info;                    die();                }                if ($this->modify_notify)                    $_SESSION['notify'] = $this->modify_notify;                if ($this->modify_redirect) {                    header('location:' . $this->modify_redirect);                    die();                }            }        }    }    private function insert($where_field = '', $where_value = '')    {        if (!empty($_POST) AND $_POST['table_name'] == $this->table_name) {            if (!$_POST['id']) {                $sql = 'INSERT INTO ' . $this->table_name . ' (';                if(isset($_POST['_wysihtml5_mode']))                    $i= 1;                else                    $i = 0;                $count = count($_POST);                foreach ($_POST AS $key => $value) {                    if ($key != 'table_name' AND $key !='_wysihtml5_mode') {                        $nouveau_field = str_replace('_submit', '', $key);                        if ($key == $nouveau_field) {                            $field = $this->db->SQLFix($key);                            $sql .= $field;                            if ($i < $count - 2)                                $sql .= ', ';                            $i++;                        }                    }                }                if ($where_field AND $where_value)                    $sql .= ', ' . $where_field;                if ($this->compte_principal)                    $sql .= ', compte_principal) VALUES (';                else                    $sql .= ') VALUES (';                if(isset($_POST['_wysihtml5_mode']))                    $i= 1;                else                    $i = 0;                foreach ($_POST AS $key => $value) {                    if ($key != 'table_name' AND $key !='_wysihtml5_mode') {                        if (in_array($key, $this->tab_date)) {                            $tab_date = explode('/', $value);                            $value = mktime(23, 59, 59, $tab_date['1'], $tab_date[0], $tab_date[2]);                        }                        if (in_array($key, $this->tab_date_time)) {                            $tab = explode(' ', $value);                            $tab_date = explode('/', $tab[0]);                            $tab_heure = explode(':', $tab[1]);                            $value = mktime($tab_heure[0], $tab_heure[1], 0, $tab_date['1'], $tab_date[0], $tab_date[2]);                        }                        if (in_array($key, $this->password_fields)) {                            $value = sha1($value);                        }                        $nouveau_field = str_replace('_submit', '', $key);                        if ($nouveau_field == $key) {                            $valeur = $this->db->SQLFix($value);                            $sql .= '"' . $valeur . '"';                            if ($i < $count - 2)                                $sql .= ', ';                            $i++;                        }                    }                }                if ($where_field AND $where_value)                    $sql .= ', "' . $where_value . '"';                if ($this->compte_principal)                    $sql .= ', "' . $_SESSION['compte_principal'] . '")';                else                    $sql .= ')';                $sql = str_replace(', ,', ', ', $sql);                //echo $sql;                $this->db->Query($sql);                if ($this->db->Error()) {                    $erreur = new Danger('MySQL a retourné une erreur : <strong>' . $this->db->Error() . '</strong> &rarr; Table "<strong>' . $this->table_name . '</strong>"', false);                    $info = new Info('Requête MySQL : <strong>' . $sql . '</strong>', false);                    echo $erreur . $info;                    die();                }                if ($this->add_notify)                    $_SESSION['notify'] = $this->add_notify;                if ($this->add_redirect) {                    header('location:' . $this->add_redirect);                    die();                }            }        }    }    public function noModifyFields($fields)    {        if (is_array($fields))            $this->no_modify_fields = $fields;        else            $this->no_modify_fields[] = $fields;    }    public function hideFields($fields)    {        if (is_array($fields))            $this->hide_fields = $fields;        else            $this->hide_fields[] = $fields;    }    public function passwordFields($fields)    {        if (is_array($fields))            $this->password_fields = $fields;        else            $this->password_fields[] = $fields;    }    public function displayedFields($fields)    {        if (is_array($fields))            $this->displayed_fields = $fields;        else            $this->displayed_fields[] = $fields;    }    public function labelsDisplayedFields($labels)    {        if (is_array($labels))            $this->labels_table = $labels;        else            $this->labels_table[] = $labels;    }    public function setOrderBy($field, $sens = 'ASC')    {        $this->order_by = $this->table_name . '.' . $field;        $this->sens_order_by = $sens;    }    public function setWidget($name, $size = 12, $boxed = false)    {        $this->widget_name = $name;        $this->widget_size = $size;        $this->widget_boxed = $boxed;    }    public function activateAdd($link_redirect = '', $notify_alias = '', $where_field = '', $where_value = '', $tab_hiddens_add='')    {        $this->add = true;        $this->add_notify = $notify_alias;        $this->add_redirect = $link_redirect;        if (is_array($tab_hiddens_add))            $this->tab_hiddens_add = $tab_hiddens_add;        $this->insert($where_field, $where_value);    }    public function activeDelete($link_redirect = '', $notify_alias = '')    {        $this->delete_notify = $notify_alias;        $this->delete_redirect = $link_redirect;        $this->delete = true;        $this->delete();    }    public function activeModify($link_redirect = '', $notify_alias = '', $tab_hiddens = '')    {        $this->modify = true;        $this->modify_notify = $notify_alias;        $this->modify_redirect = $link_redirect;        if (is_array($tab_hiddens))            $this->tab_hiddens = $tab_hiddens;        $this->update();    }    public function addWhere($where_clause)    {        $this->tab_where[] = $where_clause;    }    public function addIfValue($field, $value, $value_to_substitute, $where_field = '', $where_value = '')    {        $this->tab_ifvalue[$this->ifvaluecounter]['field'] = $field;        $this->tab_ifvalue[$this->ifvaluecounter]['value'] = $value;        $this->tab_ifvalue[$this->ifvaluecounter]['replace'] = $value_to_substitute;        $this->tab_ifvalue[$this->ifvaluecounter]['where_field'] = $where_field;        $this->tab_ifvalue[$this->ifvaluecounter]['where_value'] = $where_value;        $this->ifvaluecounter++;    }    private function form($id_form, $edit = false)    {        $form = new FormLayout('Saisie');        $form->setFormControls($id_form);        $nb_colums = $this->db->GetColumnCount();        $tab_colums = $this->db->GetColumnNames();        $hiddens = '';        $db = new MySQL();        for ($j = 0; $j < $nb_colums; $j++) {            if (!(count($this->tab_data_type_form[$tab_colums[$j]]))) {                $db->Query('SELECT DATA_TYPE, CHARACTER_MAXIMUM_LENGTH, COLUMN_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name="' . $this->table_name . '" AND COLUMN_NAME="' . $tab_colums[$j] . '" AND TABLE_SCHEMA="gi67_managy" ');                $row = $db->Row();                $this->tab_data_type_form[$tab_colums[$j]]['data'] = $row->DATA_TYPE;                $this->tab_data_type_form[$tab_colums[$j]]['possibilities'] = $row->COLUMN_TYPE;            }        }        for ($i = 0; $i < $nb_colums; $i++) {            if (false !== $key = array_search($tab_colums[$i], $this->displayed_fields)) {                $change = false;                $forced = true;                $unique = false;                foreach ($this->tab_innerjoin AS $keyinner => $inner)                    if ($inner['field_to_replace'] == $tab_colums[$i]) {                        $change = $keyinner + 1;                        $new_field = $inner['new_field'];                        $forced = $inner['forced'];                        if ($inner['unique'])                            $unique = $inner['field_to_replace'];                    }                if ($change) {                    $champs = new Select($tab_colums[$i]);                    $champs->withSearch();                    if (!$forced)                        $champs->addOption('0', '--');                    if ($edit)                        $champs->setSelected($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]);                    if (is_array($this->tab_innerjoin[$change - 1]['content']))                        foreach ($this->tab_innerjoin[$change - 1]['content'] AS $inner) {                            if ($unique) {                                $db = new MySQL();                                $sql = 'SELECT ' . $unique . ' FROM ' . $this->table_name . ' WHERE id != "' . $this->db->RecordsArray()[$edit - 1]['id'] . '" ';                                if ($this->compte_principal)                                    $sql .= ' AND compte_principal="' . $_SESSION['compte_principal'] . '" ';                                $db->Query($sql);                                $total = $db->RowCount();                                $tab_licence_used = Array();                                for ($u = 0; $u < $total; $u++) {                                    if ($db->RecordsArray()[$u][$unique] != 0)                                        $tab_licence_used[] = $db->RecordsArray()[$u][$unique];                                }                                if (in_array($inner['id'], $tab_licence_used))                                    $champs->addOption($inner['id'], $inner[$new_field], false, true);                                else                                    $champs->addOption($inner['id'], $inner[$new_field]);                            } else                                $champs->addOption($inner['id'], $inner[$new_field]);                        }                } else {                    $type_field = $this->tab_data_type_form[$tab_colums[$i]]['data'];                    $possibilites = $this->tab_data_type_form[$tab_colums[$i]]['possibilities'];                    switch ($type_field) {                        case 'varchar':                            $champs = new Text($tab_colums[$i]);                            if(in_array($tab_colums[$i], $this->tab_color_picker))                               $champs->colorPicker();                            $champs->noAutocomplete();                            if ($edit)                                $champs->setValue($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]);                            break;                        case 'enum':                            $enums = str_replace('enum(', '', $possibilites);                            $enums = str_replace(')', '', $enums);                            $enums = str_replace("'", "", $enums);                            $tab_enums = explode(',', $enums);                            $count = count($tab_enums);                            $champs = '';                            if ($count == 2) {                                if (in_array('0', $tab_enums) AND in_array('1', $tab_enums)) {                                    if ($this->maxcountvalue['field']) {                                        $sql = 'SELECT COUNT(*) AS counter FROM ' . $this->table_name . ' WHERE ' . $this->maxcountvalue['field'] . '="' . $this->maxcountvalue['value'] . '" AND id != "' . $this->db->RecordsArray()[$edit - 1]['id'] . '"';                                        if ($this->compte_principal)                                            $sql .= ' AND compte_principal = "' . $_SESSION['compte_principal'] . '"';                                        $db->Query($sql);                                        $row = $db->Row();                                        $counter = $row->counter;                                        $sql = 'SELECT ' . $this->maxcountvalue['field_max'] . ' FROM ' . $this->maxcountvalue['table'] . ' WHERE ' . $this->maxcountvalue['where_field'] . '="' . $this->maxcountvalue['where_value'] . '"';                                        $db->Query($sql);                                        $max = $db->RecordsArray()[0][$this->maxcountvalue['field_max']];                                    }                                    $radio1 = new Radio($tab_colums[$i], '0');                                    if ($edit AND $this->db->RecordsArray()[$edit - 1][$this->db->GetColumnName($i)] == '0')                                        $radio1->checked();                                    if ($this->maxcountvalue['value'] == 0 AND $counter >= $max AND count($this->maxcountvalue) > 0)                                        $radio1->disabled();                                    $radio2 = new Radio($tab_colums[$i], '1');                                    if ($this->maxcountvalue['value'] == 1 AND $counter >= $max AND count($this->maxcountvalue) > 0)                                        $radio2->disabled();                                    if ($edit AND $this->db->RecordsArray()[$edit - 1][$this->db->GetColumnName($i)] == '1')                                        $radio2->checked();                                    $champs = $radio1 . ' Non<br />' . $radio2 . ' Oui';                                } else {                                    foreach ($tab_enums AS $value) {                                        $radio = new Radio($tab_colums[$i], $value);                                        if ($edit AND $this->db->RecordsArray()[$edit - 1][$this->db->GetColumnName($i)] == $value)                                            $radio->checked();                                        $champs .= $radio . ' ' . $value . '<br />';                                    }                                }                            } else {                                if ($count > 3) {                                    $champs = new Select($tab_colums[$i]);                                    if ($edit)                                        $champs->setSelected($this->db->RecordsArray()[$edit - 1][$this->db->GetColumnName($i)]);                                    $champs->withSearch();                                    foreach ($tab_enums AS $value)                                        $champs->addOption($value, $value);                                } else {                                    foreach ($tab_enums AS $value) {                                        $radio = new Radio($tab_colums[$i], $value);                                        if ($edit AND $this->db->RecordsArray()[$edit - 1][$this->db->GetColumnName($i)] == $value)                                            $radio->checked();                                        $champs .= $radio . ' ' . $value . '<br />';                                    }                                }                            }                            break;                        case 'text':                            $champs = new Textarea($tab_colums[$i]);                            if ($edit)                                if (is_array($this->tab_ifvalue))                                    foreach ($this->tab_ifvalue AS $v)                                        if ($tab_colums[$i] == $v['field'] AND $this->db->RecordsArray()[$i][$v['where_field']] == $v['where_value'] AND ($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]] == $v['value'] OR $v['value'] == '*'))                                            $replace = $v['replace'];                            if ($replace)                                $champs->setValue($replace);                            else                                $champs->setValue($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]);                            if(in_array($tab_colums[$i], $this->tab_wysiwyg))                            {                                $champs->setRows(10);                                $champs->Wysiwyg();                            }                            $champs->elastic();                            break;                        default:                            $champs = new Text($tab_colums[$i]);                            $champs->noAutocomplete();                            if (in_array($tab_colums[$i], $this->tab_date))                                $champs->datePicker();                            if (in_array($tab_colums[$i], $this->tab_date_time))                                $champs->dateTimePicker();                            if(in_array($tab_colums[$i], $this->tab_color_picker))                                $champs->colorPicker();                            if ($edit)                                if (in_array($tab_colums[$i], $this->tab_date)) {                                    if ($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]] == '0' AND $this->if_zero_replace_by_today)                                        $champs->setValue(date('d/m/Y', time()));                                    else                                        $champs->setValue(date('d/m/Y', $this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]));                                } else {                                    if (in_array($tab_colums[$i], $this->tab_date_time))                                        $champs->setValue(date('d/m/Y H:i', $this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]));                                    else                                        $champs->setValue($this->db->RecordsArray()[$edit - 1][$tab_colums[$i]]);                                }                    }                }                if (!in_array($tab_colums[$i], $this->no_modify_fields)) {                    if (in_array($tab_colums[$i], $this->password_fields)) {                        $champs = new Password($tab_colums[$i]);                        $champs->noAutocomplete();                        if ($this->labels_table[$key])                            $form->addLine('Nouveau ' . $this->labels_table[$key], $champs);                        else                            $form->addLine('Nouveau ' . $tab_colums[$i], $champs);                    } else {                        if ($this->labels_table[$key])                            $form->addLine($this->labels_table[$key], $champs);                        else                            $form->addLine($tab_colums[$i], $champs);                    }                }            }        }        if ($edit) {            foreach ($this->tab_hiddens AS $k => $v) {                $hidden = new Hidden($k);                $hidden->setValue($v);                $hiddens .= $hidden;            }        }        else        {            foreach ($this->tab_hiddens_add AS $k => $v) {                $hidden = new Hidden($k);                $hidden->setValue($v);                $hiddens .= $hidden;            }        }        $id_entry = '';        if ($edit) {            $id_entry = new Hidden('id');            $id_entry->setValue($this->db->RecordsArray()[$edit - 1]['id']);        }        $table = new Hidden('table_name');        $table->setValue($this->table_name);        $form->addContent($hiddens . $id_entry . $table);        return $form;    }    public function getSql()    {        $this->query();        return $this->sql;    }    private function query()    {        if (in_array('id', $this->displayed_fields)) {            $sql = 'SELECT ';            $virgule = '';        } else {            $sql = 'SELECT ' . $this->table_name . '.id AS id';            $virgule = ', ';        }        $compteur = 0;        foreach ($this->displayed_fields AS $value) {            if (!$compteur)                $sql .= $virgule;            else                $sql .= ', ';            $sql .= $this->table_name . '.' . $value . ' AS ' . $value;            $compteur++;        }        foreach ($this->tab_innerjoin AS $inner)            $sql .= ', ' . $inner['table_joined'] . '.' . $inner['new_field'] . ' AS ' . $inner['table_joined'] . '_' . $inner['new_field'];        $sql .= ' FROM ' . $this->table_name;        foreach ($this->tab_innerjoin AS $inner) {            $sql .= ' LEFT JOIN ' . $inner['table_joined'] . ' ON (' . $this->table_name . '.' . $inner['field_to_replace'] . ' = ' . $inner['table_joined'] . '.id)';            if ($inner['compte_principal'])                $sql .= ' AND (' . $inner['table_joined'] . '.compte_principal = ' . $_SESSION['compte_principal'] . ')';        }        $nb_where = count($this->tab_where);        if ($nb_where) {            $i = 0;            foreach ($this->tab_where AS $value) {                if (!$i)                    $sql .= ' WHERE ' . $value;                else                    $sql .= ' AND ' . $value;                $i++;            }            if ($this->compte_principal)                $sql .= ' AND ' . $this->table_name . '.compte_principal=' . $_SESSION['compte_principal'];        } else            if ($this->compte_principal)                $sql .= ' WHERE ' . $this->table_name . '.compte_principal=' . $_SESSION['compte_principal'];        if ($this->order_by)            $sql .= ' ORDER BY ' . $this->order_by . ' ' . $this->sens_order_by;        $this->sql = $sql;    }    public function addOpenLink($value, $link, $replace_field = '', $icon = 'arrow-right', $modal = '', $condition_field = '', $condition_value = '')    {        $this->open_link[$this->compteur_open_link]['value'] = $value;        $this->open_link[$this->compteur_open_link]['link'] = $link;        $this->open_link[$this->compteur_open_link]['icon'] = $icon;        $this->open_link[$this->compteur_open_link]['modal'] = $modal;        if ($replace_field)            $this->open_link[$this->compteur_open_link]['replace'] = $replace_field;        if (is_array($condition_field))            $this->open_link[$this->compteur_open_link]['condition']['field'] = $condition_field;        else            $this->open_link[$this->compteur_open_link]['condition']['field'][] = $condition_field;        if (is_array($condition_value))            $this->open_link[$this->compteur_open_link]['condition']['value'] = $condition_value;        else            $this->open_link[$this->compteur_open_link]['condition']['value'][] = $condition_value;        $this->compteur_open_link++;    }    public function noPrintModals()    {        $this->noprintmodal = true;    }    public function printAllModals()    {        $html = '';        foreach ($this->tab_modals AS $mod)        {            $html .= $mod;        }        return $html;    }    public function __toString()    {        $this->query();        $this->db->Query($this->sql);        if ($this->debug)            $info = new Info('Requête MySQL : <strong>' . $this->sql . '</strong>', false);        else            $info = '';        if ($this->db->Error()) {            $erreur = new Danger('MySQL  a retourné une erreur : <strong>' . $this->db->Error() . '</strong> &rarr; Table "<strong>' . $this->table_name . '</strong>"', false);            $info = new Info('Requête MySQL : <strong>' . $this->sql . '</strong>', false);            $mail = new Maileur('Erreur Mysql');            $mail->setLogo();            $mail->addDest('contact@depaninfo67.com');            $mail->addExpediteur('noreply@managy.fr', 'Managy.fr');            $mail->AddTitle('Erreur MySQL');            $texte = 'Mysql à retourner une erreur<br /><br />                      <strong>Page concernée :</strong> https://www.managy.fr' . $_SERVER['REQUEST_URI'] . '<br />                      <strong>Utilisateur :</strong> ' . $_SESSION['prenom'] . '<br />                      <strong>Société :</strong> ' . $_SESSION['societe'] . '<br />                      <strong>Erreur SQL :</strong> ' . $this->db->Error() . ' &rarr; Table "<strong>' . $this->table_name . '</strong>"<br />                      <strong>Requête SQL :</strong> ' . $this->sql;            $mail->body($texte);            $mail->send();        } else            $erreur = '';        $tableau = new HtmlTable('', $this->data_table);        $tableau->addTSection('thead');        $tableau->addRow();        if ($this->displayed_fields) {            foreach ($this->displayed_fields As $key => $value) {                if ($this->labels_table[$key])                    $label = $this->labels_table[$key];                else                    $label = $value;                //echo $value;                if (!in_array($value, $this->hide_fields))                    $tableau->addCell($label, '', 'thead');            }            if ($this->delete OR $this->modify OR $this->compteur_open_link)                $tableau->addCell('Actions', '', 'thead', Array('style' => 'width:5%;'));            $nb_lines = $this->db->RowCount();            $db = new MySQL();            $tab_data_type = Array();            foreach ($this->displayed_fields As $key => $value) {                $db->Query('SELECT DATA_TYPE, CHARACTER_MAXIMUM_LENGTH, COLUMN_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name="' . $this->table_name . '" AND COLUMN_NAME="' . $value . '" AND TABLE_SCHEMA="gi67_managy" ');                $row = $db->Row();                $tab_data_type[$value]['type'] = $row->DATA_TYPE;                $tab_data_type[$value]['possibilities'] = $row->COLUMN_TYPE;            }            $tableau->addTSection('body');            for ($i = 0; $i < $nb_lines; $i++) {                $tableau->addRow();                foreach ($this->displayed_fields As $key => $value) {                    if (!in_array($value, $this->hide_fields)) {                        $replace = false;                        if (is_array($this->tab_ifvalue))                            foreach ($this->tab_ifvalue AS $v)                                if ($value == $v['field'] AND $this->db->RecordsArray()[$i][$v['where_field']] == $v['where_value'] AND ($this->db->RecordsArray()[$i][$v['field']] == $v['value'] OR $v['value'] == '*'))                                    $replace = $v['replace'];                        if ($replace)                            $tableau->addCell($replace);                        else {                            $type_field = $tab_data_type[$value]['type'];                            $possibilites = $tab_data_type[$value]['possibilities'];                            if ($type_field == 'enum') {                                $enums = str_replace('enum(', '', $possibilites);                                $enums = str_replace(')', '', $enums);                                $enums = str_replace("'", "", $enums);                                $tab_enums = explode(',', $enums);                                $count = count($tab_enums);                                if ($count == 2) {                                    if (in_array('0', $tab_enums) AND in_array('1', $tab_enums)) {                                        $reponse[0] = 'Non';                                        $reponse[1] = 'Oui';                                        $tableau->addCell($reponse[$this->db->RecordsArray()[$i][$value]]);                                    } else                                        $tableau->addCell($this->db->RecordsArray()[$i][$value]);                                } else                                    $tableau->addCell($this->db->RecordsArray()[$i][$value]);                            } else {                                if (empty($this->tab_innerjoin)) {                                    if (in_array($value, $this->tab_date))                                        $tableau->addCell(date('d/m/Y', $this->db->RecordsArray()[$i][$value]));                                    else {                                        if (in_array($value, $this->tab_date_time))                                            $tableau->addCell(parse_date($this->db->RecordsArray()[$i][$value]));                                        else {                                            if (in_array($value, $this->password_fields))                                                $tableau->addCell('*****');                                            else {                                                if (in_array($value, $this->tab_color_picker))                                                    $tableau->addCell('<div style="color:'.$this->db->RecordsArray()[$i][$value].';">'.$this->db->RecordsArray()[$i][$value].'</div>');                                                else                                                   $tableau->addCell(nl2br($this->db->RecordsArray()[$i][$value]));                                            }                                        }                                    }                                } else {                                    $change = false;                                    foreach ($this->tab_innerjoin AS $inner)                                        if ($inner['field_to_replace'] == $value)                                            $change = true;                                    if ($change)                                        $tableau->addCell($this->db->RecordsArray()[$i][$inner['table_joined'] . '_' . $inner['new_field']]);                                    else                                        if (in_array($value, $this->tab_date)) {                                            if ($this->db->RecordsArray()[$i][$value] == '0' AND $this->if_zero_replace_by_today)                                                $tableau->addCell(date('d/m/Y', time()));                                            else                                                $tableau->addCell(date('d/m/Y', $this->db->RecordsArray()[$i][$value]));                                        } else                                            if (in_array($value, $this->tab_date_time))                                                $tableau->addCell(parse_date($this->db->RecordsArray()[$i][$value]));                                            else {                                                if (in_array($value, $this->password_fields))                                                    $tableau->addCell('*****');                                                else {                                                    if (in_array($value, $this->tab_color_picker))                                                        $tableau->addCell('<span style="color:'.$this->db->RecordsArray()[$i][$value].';">'.$this->db->RecordsArray()[$i][$value].'</span>');                                                    else                                                        $tableau->addCell(nl2br($this->db->RecordsArray()[$i][$value]));                                                }                                            }                                }                            }                        }                    }                }                if ($this->delete OR $this->modify OR $this->compteur_open_link) {                    $dropdown = new DropdownButton();                    if ($this->modify) {                        $id_mod = rand(100, 10000);                        $modal_id = $this->db->RecordsArray()[$i]['id'];                        $edit = $i + 1;                        $db_tab = array();                        for($m = 0; $m < $this->db->GetColumnCount(); $m++)                            $db_tab['GetColumnName'][$m] = $this->db->GetColumnName($m);                        //print_r($db_tab);                        $settings = Array(                            'table_name' => $this->table_name,                            'modal_id' => $modal_id,                            'id_mod' => $id_mod,                            'edit' => $edit,                            'nb_columns' => $this->db->GetColumnCount(),                            'tab_columns' => $this->db->GetColumnNames(),                            'RecordsArray' => $this->db->RecordsArray(),                            'tab_data_type_form' => $this->tab_data_type_form,                            'displayed_fields' => $this->displayed_fields,                            'tab_innerjoin' => $this->tab_innerjoin,                            'compte_principal' => $this->compte_principal,                            'tab_color_picker' => $this->tab_color_picker,                            'tab_date' => $this->tab_date,                            'tab_date_time' => $this->tab_date_time,                            'no_modify_fields' => $this->no_modify_fields,                            'password_fields' => $this->password_fields,                            'labels_table' => $this->labels_table,                            'maxcountvalue' => $this->maxcountvalue,                            'tab_wysiwyg' => $this->tab_wysiwyg,                            'if_zero_replace_by_today' => $this->if_zero_replace_by_today,                            'tab_hiddens' => $this->tab_hiddens,                            'tab_hiddens_add' => $this->tab_hiddens_add,                            'db_tab' => $db_tab,                            'titre' => 'Modifier un élément'                        );                        $modal_edit = new modalAjax('databaseworker', 'edit', $id_mod);                        $modal_edit->settings($settings);                        //$modal_edit->setDebug();                        $dropdown->addSubButton(new Font('pencil').' Modifier', $modal_edit->getHref());                    }                    if ($this->delete)                        $dropdown->addSubButton(new Font('remove').' Supprimer', 'javascript:void();', "if(confirm('Êtes vous sûr de vouloir supprimer cet élément ?')) document.location.href='?delete=" . $this->table_name . "." . $this->db->RecordsArray()[$i]['id'] . "';");                    $modals = '';                    for ($c = 0; $c < $this->compteur_open_link; $c++) {                        $afficher = false;                        $total_tableau = count($this->open_link[$c]['condition']['field']);                        if ($total_tableau) {                            $compteur_tableau = 0;                            foreach ($this->open_link[$c]['condition']['field'] AS $kf => $vf)                                if ($this->db->RecordsArray()[$i][$vf] == $this->open_link[$c]['condition']['value'][$kf])                                    $compteur_tableau++;                            if ($compteur_tableau == $total_tableau)                                $afficher = true;                        } else                            $afficher = true;                        if ($this->open_link[$c]['replace']) {                            $link = str_replace('$', $this->db->RecordsArray()[$i][$this->open_link[$c]['replace']], $this->open_link[$c]['link']);                            $modal = str_replace('$', $this->db->RecordsArray()[$i][$this->open_link[$c]['replace']], $this->open_link[$c]['modal']);                        } else {                            $link = $this->open_link[$c]['link'];                            $modal = $this->open_link[$c]['modal'];                        }                        $modals .= $modal;                        if ($afficher)                            $dropdown->addSubButton(new Font($this->open_link[$c]['icon']).' ' . $this->open_link[$c]['value'], $link);                    }                    if ($this->modify) {                        if($this->noprintmodal) {                            $this->tab_modals[] = $modal_edit->getModalHtml();                            $tableau->addCell($dropdown   . $modals);                        }                        else                            $tableau->addCell($dropdown . $modal_edit->getModalHtml() . $modals);                    }                    else                        $tableau->addCell($dropdown);                }            }        }        $widget = new WidgetBox($this->widget_name, $this->widget_size);        if ($this->add) {            $random_id = rand(1, 10000);            $modal_id = rand(1, 10000);            $id_mod = 'add';            $edit = 0; // $i + 1;            $db_tab = array();            for($m = 0; $m < $this->db->GetColumnCount(); $m++)                $db_tab['GetColumnName'][$m] = $this->db->GetColumnName($m);            //print_r($db_tab);            $settings = Array(                'table_name' => $this->table_name,                'modal_id' => $modal_id,                'id_mod' => $id_mod,                'edit' => $edit,                'nb_columns' => $this->db->GetColumnCount(),                'tab_columns' => $this->db->GetColumnNames(),                'RecordsArray' => $this->db->RecordsArray(),                'tab_data_type_form' => $this->tab_data_type_form,                'displayed_fields' => $this->displayed_fields,                'tab_innerjoin' => $this->tab_innerjoin,                'compte_principal' => $this->compte_principal,                'tab_color_picker' => $this->tab_color_picker,                'tab_date' => $this->tab_date,                'tab_date_time' => $this->tab_date_time,                'no_modify_fields' => $this->no_modify_fields,                'password_fields' => $this->password_fields,                'labels_table' => $this->labels_table,                'maxcountvalue' => $this->maxcountvalue,                'tab_wysiwyg' => $this->tab_wysiwyg,                'if_zero_replace_by_today' => $this->if_zero_replace_by_today,                'tab_hiddens' => $this->tab_hiddens,                'tab_hiddens_add' => $this->tab_hiddens_add,                'db_tab' => $db_tab,                'titre' => 'Ajouter un élément'            );           /* if($_SESSION['id'] == 1)            {                echo '<pre>';                print_r($this->tab_ifvalue);                echo '</pre>';            }*/            /*if($_SESSION['id'] == 1)                $settings = Array(                    'table_name' => $this->table_name,                    'modal_id' => $modal_id,                    'id_mod' => $id_mod,                    'edit' => $edit,                    'nb_columns' => $this->db->GetColumnCount(),                    'tab_columns' => $this->db->GetColumnNames(),                    'RecordsArray' => $this->db->RecordsArray(),                    'tab_data_type_form' => $this->tab_data_type_form,                    'displayed_fields' => $this->displayed_fields,                    'tab_innerjoin' => $this->tab_innerjoin,                    'compte_principal' => $this->compte_principal,                    'tab_color_picker' => $this->tab_color_picker,                    'tab_date' => $this->tab_date,                    'tab_date_time' => $this->tab_date_time,                    'no_modify_fields' => $this->no_modify_fields,                    'password_fields' => $this->password_fields,                    'labels_table' => $this->labels_table,                    'maxcountvalue' => $this->maxcountvalue,                    'tab_ifvalue' => $this->tab_ifvalue,                    'tab_wysiwyg' => $this->tab_wysiwyg,                    'if_zero_replace_by_today' => $this->if_zero_replace_by_today,                    'tab_hiddens' => $this->tab_hiddens,                    'tab_hiddens_add' => $this->tab_hiddens_add,                    'db_tab' => $db_tab,                    'titre' => 'Ajouter un élément'                );*/           /* if(0) //SION['id'] == 1)////            {                echo '<pre>';                print_r($settings);                echo '</pre>';                die();            }*/            $modal_new = new modalAjax('databaseworker', 'edit', $random_id);            $modal_new->settings($settings);            //$modal_new->setDebug();            $modal_new->oppenButton(new Font('plus'), 'btn-primary');            $widget->addToolbarButtons($modal_new->getModalOpen());            if($this->noprintmodal) {                $this->tab_modals[] = $modal_new->getModalHtml();                $widget->setContent($tableau, $this->widget_boxed);            }            else                $widget->setContent($tableau . $modal_new->getModalHtml(), $this->widget_boxed);        } else            $widget->setContent($tableau, $this->widget_boxed);        $col = new Col($this->widget_size);        $col->setContent($erreur . $info);        if(is_object($erreur) AND is_object($info))            return (string)$col . $widget;        else            return (string)$widget;    }}